changeSet.sql:
CREATE TABLE payment_term ( id BIGSERIAL PRIMARY KEY, code VARCHAR(50) NOT NULL UNIQUE, name VARCHAR(255) NOT NULL, description TEXT, active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE payment_term_line ( id BIGSERIAL PRIMARY KEY, payment_term_id BIGINT NOT NULL,
value_type VARCHAR(20) NOT NULL, value_amount NUMERIC(10,2),
due_type VARCHAR(20) NOT NULL, days INT DEFAULT 0,
sequence INT NOT NULL DEFAULT 1,
CONSTRAINT fk_payment_term FOREIGN KEY (payment_term_id) REFERENCES payment_term(id) ON DELETE CASCADE );
CREATE INDEX idx_payment_term_line_term ON payment_term_line(payment_term_id);
CREATE INDEX idx_payment_term_line_sequence ON payment_term_line(sequence);
INSERT INTO payment_term (code, name) VALUES ('CASH', 'الدفع نقداً');
INSERT INTO payment_term_line ( payment_term_id, value_type, due_type, days, sequence ) VALUES ( (SELECT id FROM payment_term WHERE code='CASH'), 'balance', 'days_after_invoice', 0, 1 );
